# 输入获取
n, m = map(int, input().split())  # // 长n -> 行数, 宽m -> 列数
matrix = [list(map(int, input().split())) for _ in range(n)]  # 地图矩阵


# 算法入口
def getResult():
    # 如果起点和终点不能参观,则没有路径
    if matrix[0][0] == 1 or matrix[n - 1][m - 1] == 1:
        return 0

    dp = [[0 for _ in range(m)] for _ in range(n)]
    dp[0][0] = 1

    for i in range(n):
        for j in range(m):
            if matrix[i][j] == 1:
                continue

            if i > 0:
                dp[i][j] += dp[i - 1][j]

            if j > 0:
                dp[i][j] += dp[i][j - 1]

    return dp[n - 1][m - 1]


# 算法调用
print(getResult())
